using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API (JSONPlaceholder as an example).
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// automatically because they are registered DI services, not tool parameters.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a single post by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1–100).")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);

        var post = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts/{postId}", cancellationToken);

        return JsonSerializer.Serialize(post, JsonOptions);
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID. Omit to list all posts.")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
        logger.LogInformation("Listing posts: {Url}", url);

        var posts = await httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        return JsonSerializer.Serialize(posts, JsonOptions);
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Search posts whose title or body contains the given text.")]
    public async Task<string> SearchPosts(
        [Description("Case-insensitive text to search for in post titles and bodies.")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching posts for '{Query}'", query);

        var posts = await httpClient.GetFromJsonAsync<JsonElement[]>("posts", cancellationToken)
            ?? [];

        var matches = posts.Where(p =>
            (p.GetProperty("title").GetString() ?? "").Contains(query, StringComparison.OrdinalIgnoreCase) ||
            (p.GetProperty("body").GetString() ?? "").Contains(query, StringComparison.OrdinalIgnoreCase));

        return JsonSerializer.Serialize(matches, JsonOptions);
    }

    [McpServerTool(Destructive = true),
     Description("Create a new post. Returns the created post with its assigned ID.")]
    public async Task<string> CreatePost(
        [Description("Title of the new post.")] string title,
        [Description("Body content of the new post.")] string body,
        [Description("User ID of the post author.")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);

        var response = await httpClient.PostAsJsonAsync("posts",
            new { title, body, userId }, cancellationToken);

        response.EnsureSuccessStatusCode();
        var created = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);

        return JsonSerializer.Serialize(created, JsonOptions);
    }
}

